const SB_URL = $('Config').first().json.SUPABASE_URL;
const SB_KEY = $('Config').first().json.SUPABASE_SERVICE_KEY;
const headers = {
  'apikey': SB_KEY,
  'Authorization': 'Bearer ' + SB_KEY,
  'Content-Type': 'application/json'
};

async function sbGet(path) {
  const res = await fetch(SB_URL + '/rest/v1/' + path, { headers });
  return res.json();
}

async function sbPost(path, body) {
  await fetch(SB_URL + '/rest/v1/' + path, {
    method: 'POST',
    headers: { ...headers, 'Prefer': 'return=minimal' },
    body: JSON.stringify(body)
  });
}

async function sbPatch(path, body) {
  await fetch(SB_URL + '/rest/v1/' + path, {
    method: 'PATCH',
    headers,
    body: JSON.stringify(body)
  });
}

// 1. Query pending handoff tasks whose scheduled_at has passed
const now = new Date().toISOString();
const tasks = await sbGet(
  'follow_up_tasks?status=eq.pending&task_type=eq.handoff_reminder' +
  '&scheduled_at=lte.' + now +
  '&select=id,organization_id,lead_id,conversation_id,sequence_stage' +
  '&limit=50'
);

if (!tasks.length) {
  return [{ json: { processed: 0, message: 'No pending handoff tasks' } }];
}

// 2. Bulk-fetch lead statuses + handoff_at
const leadIds = [...new Set(tasks.map(t => t.lead_id).filter(Boolean))];
const leads = leadIds.length
  ? await sbGet('leads?id=in.(' + leadIds.join(',') + ')&select=id,status,handoff_at')
  : [];
const leadMap = {};
for (const l of leads) leadMap[l.id] = l;

let notified = 0;
let cancelled = 0;

// 3. Process each task
for (const task of tasks) {
  const lead = leadMap[task.lead_id];

  if (!lead || lead.status !== 'handed_off') {
    // Lead status changed — cancel
    await sbPatch('follow_up_tasks?id=eq.' + task.id, { status: 'cancelled' });
    cancelled++;
    continue;
  }

  // 4. Check if salesperson already replied after handoff
  const handoffAt = lead.handoff_at || '1970-01-01T00:00:00Z';
  const humanMsgs = await sbGet(
    'messages?conversation_id=eq.' + task.conversation_id +
    '&role=eq.assistant&created_at=gte.' + handoffAt +
    '&select=id&limit=1'
  );

  if (humanMsgs.length > 0) {
    // Salesperson already responded — cancel
    await sbPatch('follow_up_tasks?id=eq.' + task.id, { status: 'cancelled' });
    cancelled++;
    continue;
  }

  // 5. Still waiting — send reminder notification
  const title = task.sequence_stage === 'handoff_check_4h'
    ? 'Lead bekliyor \u2014 4 saat oldu'
    : '\u26A0\uFE0F Lead 24 saattir bekliyor!';

  await sbPost('notifications', {
    organization_id: task.organization_id,
    type: 'handoff_reminder',
    title: title,
    body: 'Handoff sonras\u0131 hen\u00FCz takip yap\u0131lmad\u0131.',
    lead_id: task.lead_id,
    conversation_id: task.conversation_id
  });

  await sbPatch('follow_up_tasks?id=eq.' + task.id, {
    status: 'done',
    sent_at: now
  });
  notified++;
}

return [{ json: { processed: tasks.length, notified, cancelled } }];
